window.__QUIZ_DATA__=[{"id":"objective>Geography>2009>1","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scale of the map is","images":["data:image/png;base64,"],"options":{"A":"1:50,000","B":"1:100,000","C":"1:150,000","D":"1:200,000"},"answer":"B","explanation":"The scale of the map is 1 : 100,000 using the linear scale given on the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>2","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The approximate distance 'as the crow flies' from Iso to Julo is","images":["data:image/png;base64,"],"options":{"A":"3.0km","B":"4.0km","C":"5.0km","D":"6.0km"},"answer":"D","explanation":"The approximate distance 'as the crow flies from Iso to Julo is 6km. Using a ruler, the distance is 6cm  1 : 100,000 = 1cm = 1000m or 1 km'  6 \u00d7 1 km = 6 km","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>3","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"The major activity of the people in the southern part of the map is likely to be","images":["data:image/png;base64,"],"options":{"A":"lumbering","B":"farming","C":"animal rearing","D":"mining"},"answer":"C","explanation":"The major activity of the people in the southern part of the map is likely to be animal rearing due to the excess grassland for grazing.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>4","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Oka can best be described as a","images":["data:image/png;base64,"],"options":{"A":"mining town","B":"gap town","C":"confluence town","D":"nodal town"},"answer":"A","explanation":"Oka can best be described as a mining town due to mineral workings described with it from the map.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>5","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The feature marked X is a","images":["data:image/png;base64,"],"options":{"A":"dam","B":"hydro-electric power station","C":"man-made lake","D":"pond"},"answer":"A","explanation":"The feature marked X is a dam  (Fully noticed with the key specified)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>6","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The symbol \u0394912 on the map is a","images":["data:image/png;base64,"],"options":{"A":"telegraph office","B":"trigonometrical station","C":"bench mark","D":"boundary pillar"},"answer":"B","explanation":"The symbol \u0394912 on the map is a triangulation station (trigonometrical station) which is a fixed surveying station, used in geodetic surveying and surveying projects in its vicinity.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>7","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The contour interval on the map is","images":["data:image/png;base64,"],"options":{"A":"50 m","B":"100 m","C":"150 m","D":"200 m"},"answer":"B","explanation":"The contour interval on the map is showing100 m    .","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>8","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The highest point on the map is slightly above","images":["data:image/png;base64,"],"options":{"A":"600m","B":"800m","C":"900m","D":"1,000m"},"answer":"C","explanation":"The highest point on the map is slightly above 900m.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>9","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following is most likely to a major problem confronting the mining industry in the mapped area?","images":["data:image/png;base64,"],"options":{"A":"Availability of labour","B":"Inadequate transportation facilities","C":"Depth of the mines","D":"Insufficient spare parts"},"answer":"B","explanation":"The most likely major problem confronting the mining industry in the mapped area is inadequate transport facilities.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>10","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"The area covered by ALELE DISTRICT is approximately","images":["data:image/png;base64,"],"options":{"A":"205 km2","B":"230 km2","C":"235 km2","D":"248 km2"},"answer":"D","explanation":"Area covered by ALELE DISTRICT  Scale is 1 : 100,000 and 1cm = 1000km  Sum of distances - Width = 15.5cm  - Length = 16cm  Equivalent ground distance: Width = 15.5 \u00d7 1000  \u21d2 15,500km  Length = 16 \u00d7 1000  \u2234 The Area of ALELE DISTRICT; = 16000km  \u21d2 16000 \u00d7 15500  = 248km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>11","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which two planets lie between the sun and the earth?","images":[],"options":{"A":"Venus and Mars","B":"Venus and Jupitar","C":"Mercury and Venus","D":"Mercury and Saturn"},"answer":"C","explanation":"The two planets that lie between the sun and the earth are Mercury and Venus. This is based on the order of the planets in the solar system from the sun, which is Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, and Neptune.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>12","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"On June 21st, when the sun is overhead at the Tropic of Cancer, places in the Northern Hemisphere experience","images":[],"options":{"A":"longer day and shorter night","B":"twilight","C":"shorter day and longer night","D":"longer day and night"},"answer":"A","explanation":"On June 21st, when the sun is overhead at the Tropic of Cancer, places in the Northern Hemisphere experience longer day and shorter night.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>13","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"When a ship appears over the distant horizon the","images":[],"options":{"A":"hull is seen before the cabin","B":"hull and the mast are seen together","C":"mast is seen before the hull","D":"cabin is seen before the mast"},"answer":"C","explanation":"When a ship appears over the distant horizon, the most is seen before the hull which is as a result of the shape of the earth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>14","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The innermost section of the Earth is the","images":[],"options":{"A":"core","B":"mantle","C":"crust","D":"sial"},"answer":"A","explanation":"The Earth is divided into three main layers: the crust, the mantle, and the core. The core is the innermost section of the Earth. It is composed mainly of iron and nickel and is divided into two parts: the inner core and the outer core.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>15","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following is not a characteristic of sedimentary rocks? They","images":[],"options":{"A":"contain fossils","B":"are crystalline","C":"are usually laid down in layers","D":"are porous"},"answer":"B","explanation":"Sedimentary rocks are usually not crystalline. They are formed from the accumulation of sediments, such as sand, silt, and clay, or the remains of plants and animals. These materials are compressed over time to form layers. Sedimentary rocks often contain fossils and are usually porous.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>16","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Rocks which have been formed by the cooling and solidification of molten magma are called","images":[],"options":{"A":"igneous rocks","B":"sedimentary rocks","C":"conglomerates","D":"metamorphic rocks"},"answer":"A","explanation":"Igneous rocks are formed from the solidification of molten magma or lava. This process can occur either beneath the Earth's crust (forming intrusive igneous rocks) or on the surface (forming extrusive igneous rocks).","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>17","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following is not a type of mountain?","images":[],"options":{"A":"Conical mountain","B":"Block mountain","C":"Fold mountain","D":"Mountain of accumulation"},"answer":"A","explanation":"Cornical mountain is not a type of mountain. Other option listed are types of mountain.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>18","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not true of stalagmites and stalactites?","images":[],"options":{"A":"Stalagmites are upward growing pillars while stalactites are downward growing","B":"Stalagmites are short and wide while stalactiles are long and narrow","C":"Stalactiles are formed on the floor of limestone caves while stalagmites are formed on roofs of limestone caves","D":"Stalactiles are longer than stalagmites"},"answer":"C","explanation":"Stalagmites rises from the floor of a cave due to the accumulation of a material deposited on the floor from ceiling drippings while staleate are downward growing.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>19","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following pairs are desert landforms?","images":[],"options":{"A":"Wave-cut plalforms and self dunes","B":"Sandbars and sandspits","C":"Yardangs and zeugens","D":"Barchans and tombolos"},"answer":"C","explanation":"Desert landforms are rock pedestals, deflation hollows, oasis, sand dunes, yardangs, zeugen and desert pavements.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>20","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Most of the world's lakes are fresh water lakes which are","images":[],"options":{"A":"fed by rivers with outlets to the sea","B":"fed by melting glaciers","C":"fairly saline due to excessive evaporation","D":"constant in volume"},"answer":"A","explanation":"Most of the world's lakes are fresh water lakes which are fed by rivers with outlets to the sea.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>21","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A geyser is best described as a/an","images":[],"options":{"A":"pool of hot water","B":"explosion of volcano","C":"thermal stream","D":"fountain of super heated stream"},"answer":"D","explanation":"A geyser a hot spring in which water intermittently boils, sending a tall column of water and steam into the air (fountain of super heated stream).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>22","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Figure 1 above represents a","images":["data:image/png;base64,"],"options":{"A":"pie chart","B":"flow line map","C":"dot map","D":"simple graph"},"answer":"B","explanation":"The figure 1 represents a flow line map because it denote the direction of a phenomenon being moved from one location to another","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>23","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"What is the volume of passenger traffic between IZABU and Ashama?","images":["data:image/png;base64,"],"options":{"A":"12,000","B":"10,000","C":"8,000","D":"6,000"},"answer":"A","explanation":"No of lines between IZABU and Ashama = 8  1 Line represents, 1500 persons   8 Lines = (8 \u00d7 1500) persons  \u21d2 12,000 persons","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>24","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"By how much traffic between IZABU and Anikpu more than the traffi etween IZABU and Ugba?","images":["data:image/png;base64,"],"options":{"A":"1,800","B":"1,700","C":"1,500","D":"1,200"},"answer":"C","explanation":"No of lines between IZABU and Anikpu = 5  \u21d2 5 \u00d7 1500 = 7,500 persons   No of lines between IZABU and Ugba = 4  \u21d2 4 \u00d7 1500 = 6,000 persons   Traffic between = (5 - 4) or 7,500 - 6,000  \u21d2 1,500 persons.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>25","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Which of the following is not true of pie chart?","images":[],"options":{"A":"Statistics of various items can be represented on a single diagram","B":"It is often difficult to compare the component parts","C":"Data with wide extremes can be conveniently represented in a pie chart","D":"It is easy to draw"},"answer":"C","explanation":"A pie chart is not suitable for data with wide extremes because it becomes difficult to make accurate comparisons between categories. A pie chart represents data as a proportion of a whole, so if the data has wide extremes, the smaller categories may not be visible or may be difficult to compare.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>26","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The climatic belts recognized by the Greek were","images":[],"options":{"A":"torrid, temperature and frigid","B":"hot, cold and medium","C":"hot, mild and cool","D":"equatorial, polar and torrid"},"answer":"A","explanation":"The Greeks were among the first set of people in the world to classify climates. Their scheme divided the world into three zones based on temperature (Torrid or Hot, Frigid or very cold, Temperate or Mild).","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>27","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A mercury barometer is used for measuring","images":[],"options":{"A":"wind speed","B":"temperature","C":"sunshine","D":"atmospheric pressure"},"answer":"D","explanation":"A mercury barometer is used to measure atmospheric pressure. It works by balancing the weight of mercury in the tube against the atmospheric pressure, much like a standard balance scale. When the atmospheric pressure is high, it pushes the mercury higher in the tube.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>28","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Lines joining places with same mean annual rainfall are called","images":[],"options":{"A":"isohyets","B":"isohels","C":"isohalines","D":"isotherms"},"answer":"A","explanation":"Isohyets are lines on a map connecting areas that receive equal amounts of rainfall. This term comes from the Greek words 'isos' meaning equal and 'hyetos' meaning rain.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>29","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A line joining places having an equal degree of cloudiness is an","images":[],"options":{"A":"isotherm","B":"isohyets","C":"isobar","D":"isoneph"},"answer":"D","explanation":"Isoneph is a line on a map connecting points that have the same average percentage of cloudiness i.e equal degree of cloudiness.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>30","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following winds affects the West Indian islands of the Caribbean?","images":[],"options":{"A":"Hurricanes","B":"Mistral","C":"Chinook","D":"Tornadoes"},"answer":"A","explanation":"The Hurricanes affects the West Indian islands of the caribbean by forming around areas of extremely low pressure over warm ocean waters (like those in the Caribbean and South Atlantic) in the summer and fall.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>31","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Loess is an example of","images":[],"options":{"A":"clayey soil","B":"loamy soil","C":"wind deposited soil","D":"montane soil"},"answer":"C","explanation":"Loess is a loosely compacted yellowish-grey deposit of wind-blown sediment of which extensive deposits occurs e.g in eastern china and the American Midwest.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>32","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"A soil profile refers to the","images":[],"options":{"A":"shape of the soil","B":"vertical section of the soil","C":"mineral composition of the soil","D":"zone of eluviation"},"answer":"B","explanation":"Soil profile is refers to as the vertical section of the soil, showing series of horizontal layers of different types of soil.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>33","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"\"The trees are evergreen, forming a canopy with buttress roots, climbers and creepers\". Which of the following vegetation types does this statement refers to?","images":[],"options":{"A":"Savanna","B":"Equatorial","C":"Tropical desert","D":"Mediterranean"},"answer":"B","explanation":"In Equatorial vegetation, the trees are evergreen, forming a canopy with buttress roots, climbers and creepers.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>34","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Which of the following environmental hazards is due primarily to human activities?","images":[],"options":{"A":"Earthquake","B":"Volcanic eruption","C":"Hurricane","D":"Ozone depletion"},"answer":"D","explanation":"Ozone depletion is due primarily to human activities through the use of chloroflorocarbon (CFC) in air conditioners and sprays.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>35","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Life expectancy refers to the","images":[],"options":{"A":"age at which people receive their pension","B":"average age at which people die","C":"achievement one makes in life","D":"age at which people retire from their jobs"},"answer":"B","explanation":"Life expectancy refers to the average age at which people die. It is a statistical measure of the average time an organism is expected to live, based on the year of its birth, its current age, and other demographic factors including gender.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>36","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The term over-population is best defined as the situation where","images":[],"options":{"A":"there is high population density","B":"birth rate is equal to death rate","C":"the population exceeds available resources","D":"there is an increasing birth rate and a decreasing infant mortality rate"},"answer":"C","explanation":"Over-population is best defined as the situation where the population exceeds available resources. This means that the number of people in an area exceeds the resources available to meet their needs, leading to a decline in living standards, environmental degradation, and other negative outcomes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>37","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following features is shared by Hong Kong, Java and Manhattan?","images":[],"options":{"A":"High military technology","B":"High population density","C":"Multi-racial communities","D":"Rapid industrial growth"},"answer":"B","explanation":"Hong Kong, Java, and Manhattan are all known for their high population density. This means that these areas have a large number of people living in a relatively small space. This is often due to factors such as economic opportunities, availability of services, and transportation infrastructure.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>38","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A conurbation can best be described as","images":[],"options":{"A":"a large village with thousands of people","B":"two or more towns joined together, each town maintaining its own identity","C":"a large area with big cities","D":"a big area of land with few settlements"},"answer":"B","explanation":"A conurbation can be best described as two or more towns joined together, each town maintaining its own identity.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>39","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A settlement developed at the meeting point of roads is known as a","images":[],"options":{"A":"port town","B":"nodal town","C":"gap town","D":"confluence town"},"answer":"B","explanation":"A settlement developed at the meeting points of roads is known as a nodal town because it possess both characteristics of a compact settlement and an ordered settlement pattern that surround it.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>40","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"'It is a port that specializes in receiving and redistributing goods to the neighbouring countries'. Which of the following ports is described in the preceding statement?","images":[],"options":{"A":"Ferry port","B":"Outport","C":"River port","D":"Entrepot"},"answer":"D","explanation":"An Entrepot is a port that specializes in receiving and redistributing goods to the neighbouring countries.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>41","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The ocean that connects Europe and America is the","images":[],"options":{"A":"Indian ocean","B":"Antarctic ocean","C":"Atlantic ocean","D":"Arctic ocean"},"answer":"C","explanation":"The Atlantic Ocean is the second largest of the world's oceans, and it separates the continents of North America and Europe, hence it connects Europe and America.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>42","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Copper is an important raw material in the","images":[],"options":{"A":"chemical industry","B":"oil refining industry","C":"pharmaceutical industry","D":"electrical industry"},"answer":"D","explanation":"Copper is an important raw material in the electrical industry because of it does not support corrosion, it extreme conductivity and ductility.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>43","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which activity requires the following?  I. Large area of land usually in thousands of hectares  II. Availability of water either in form of rain or irrigation  III. High capital outlay","images":[],"options":{"A":"Plantation agriculture","B":"Mining","C":"Lumbering","D":"Tourism industry"},"answer":"A","explanation":"Plantation agriculture requires a large area of land, usually in thousands of hectares, for the cultivation of a single crop. It also requires a significant amount of water, either in the form of rain or irrigation, to sustain the crops. Additionally, plantation agriculture involves a high capital outlay for the purchase of land, machinery, and labor.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>44","subject":"Geography","year":"2009","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"A great advantage of basin irrigation is that","images":[],"options":{"A":"it makes it possible to irrigate larger areas","B":"the basin helps to trap much alluvium to enrich the soil","C":"it is an expensive means of irrigation","D":"water is not wasted"},"answer":"A","explanation":"A great advantage of basin irrigation is that it makes it possible to irrigate larger areas.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>45","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"The Gezira Scheme and the Manaquil Extension are famous for the cultivation of","images":[],"options":{"A":"kolanuts","B":"cotton","C":"sugar cane","D":"beans and other legumes"},"answer":"B","explanation":"The Gezira Scheme and the Manaquil Extension are irrigation projects in Sudan, known for the cultivation of cotton. The Gezira Scheme is one of the largest irrigation projects in the world, and it primarily supports the cultivation of cotton, but also grows wheat and other crops.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>46","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The system of cultivation of tropical commercial crops on large estates is known as","images":[],"options":{"A":"plantation agriculture","B":"bush fallowing","C":"mixed cropping","D":"intensive farming"},"answer":"A","explanation":"Plantation agriculture refers to the industrial farming system where one crop is grown on a large scale. It is particularly prevalent in the tropics, where commercial crops such as coffee, cocoa, rubber, sugarcane, banana, and pineapple are commonly grown.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2009>47","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"All the following are problems of mining in Africa except","images":[],"options":{"A":"use of obsolete technology","B":"inadequate foreign capital","C":"shortage of power","D":"inadequate unskilled labour"},"answer":"D","explanation":"Inadequate unskilled labour is not a problem of mining in Africa. In fact, Africa has a large labour force. The other options such as use of obsolete technology, inadequate foreign capital, and shortage of power are indeed problems faced by the mining industry in Africa.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2009>48","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The most common moe of transportation in Africa is","images":[],"options":{"A":"air","B":"rail","C":"ocean","D":"road"},"answer":"D","explanation":"The most common mode of transportation in Africa is road. This is due to the fact that road networks cover more areas compared to other modes of transportation like air, rail, and ocean. Roads are used for both short and long distance travel, and they connect rural and urban areas.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>49","subject":"Geography","year":"2009","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The longest river in Africa is River","images":[],"options":{"A":"Congo","B":"Zambezi","C":"Senegal","D":"Nile"},"answer":"D","explanation":"The longest river in Africa is the Nile River. It is approximately 4,135 miles long, making it the longest river in Africa and the second longest in the world.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2009>50","subject":"Geography","year":"2009","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Africa's largest timber producer is","images":[],"options":{"A":"Zaire","B":"Ghana","C":"Nigeria","D":"Malawi"},"answer":"A","explanation":"Africa's largest timber producer is Zaire. Zaire, now known as the Democratic Republic of the Congo (DRC), has historically been one of the largest timber producers in Africa due to its vast tropical rainforests, particularly the Congo Basin. The Congo Basin is the second-largest tropical rainforest in the world, after the Amazon, and is a significant source of timber and other forest products.","marks":"1","difficulty":"2"}];